                          {order.status}
                        </span>

                        {/* Quick action buttons next to status text (only for admin) */}
                        {isAdmin && order.status === "Chờ duyệt" && (
                          <button 
                            onClick={e => { e.stopPropagation(); handleChangeStatus(order.id, "Đang giao") }}
