      {viewingOrder && (
        <OrderDetailModal 
          order={viewingOrder} 
          onClose={() => setViewingOrder(null)} 
        />
      )}

      {updatingOrder && (
        <UpdateOrderStatusModal 
          order={updatingOrder}
          onSave={handleChangeStatus}
          onClose={() => setUpdatingOrder(null)}
        />
